// Uses Web Crypto API (no require('crypto') needed — works in n8n sandbox)
const secret = 'YOUR_TEXTBEE_WEBHOOK_SECRET';

const body = $input.first().json.body;
const received = (
  ($input.first().json.headers && ($input.first().json.headers['x-signature'] || $input.first().json.headers['X-Signature'])) || ''
).toLowerCase();

const signatureEnforced = false;
if (!received) {
  if (signatureEnforced) throw new Error('Missing TextBee signature — request rejected');
  console.warn('WARNING: No TextBee signature — proceeding without verification (testing mode)');
} else if (signatureEnforced) {
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    'raw', encoder.encode(secret), { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']
  );
  // TextBee signs JSON.stringify(payload) where payload = parsed request body
  const sigBuffer = await crypto.subtle.sign('HMAC', key, encoder.encode(JSON.stringify(body)));
  const expected = Array.from(new Uint8Array(sigBuffer))
    .map(b => b.toString(16).padStart(2, '0')).join('');
  if (expected !== received) {
    throw new Error('Invalid TextBee signature — request rejected');
  }
}

// Normalize MESSAGE_SENT → MESSAGE_DELIVERED
let webhookEvent = body.webhookEvent || '';
if (webhookEvent === 'MESSAGE_SENT') webhookEvent = 'MESSAGE_DELIVERED';

return [{ json: {
  webhookEvent,
  recipient:     body.recipient || '',
  message:       body.message || '',
  deliveredAt:   body.deliveredAt || body.sentAt || '',
  failedAt:      body.failedAt || '',
  errorMessage:  body.errorMessage || '',
  errorCode:     body.errorCode || '',
  sender_phone:  body.sender || body.from || body.phoneNumber || body.senderNumber ||
                 (body.data && (body.data.sender || body.data.phoneNumber)) || '',
  message_text:  body.message || body.body || body.text ||
                 (body.data && (body.data.message || body.data.text)) || '',
  raw_timestamp: body.receivedAt || body.createdAt || body.timestamp ||
                 (body.data && (body.data.receivedAt || body.data.createdAt)) || '',
}}];

const NZT_OFFSET = 13; // NZDT (UTC+13)

function normalizeForMatch(phone) {
  if (!phone) return '';
  return phone.replace(/[\s\-\(\)]/g, '')
              .replace(/^\+64/, '0')
              .replace(/^64/, '0');
}

function toNZTStr(rawTime) {
  // If no timestamp (MESSAGE_SENT has none), fall back to current NZT time
  const base = rawTime ? new Date(rawTime) : new Date();
  const dt = (!rawTime || isNaN(base)) ? new Date() : base;
  const nzt = new Date(dt.getTime() + NZT_OFFSET * 3600000);
  return nzt.toISOString().slice(0, 16).replace('T', ' ');
}

function getModeFromMessage(msg) {
  if (msg.includes('Worth a chat?'))       return 'Initial Sent';
  if (msg.includes('just following up'))   return 'F1 Sent';
  if (msg.includes('Last one from me'))    return 'F2 Sent';
  return null;
}

const parsed = $('Verify & Parse').item.json;
const recipientNorm = normalizeForMatch(parsed.recipient);

// Find matching lead row first
const rows = $input.all();
let matchRow = null;
for (const item of rows) {
  if (normalizeForMatch(item.json['Mobile'] || '') === recipientNorm) {
    matchRow = item.json;
    break;
  }
}
if (!matchRow) return [];

const tsCol = getModeFromMessage(parsed.message);

if (!tsCol) {
  // Brandon's manual reply from TextBee — increment Brandon_Replies and queue for Conversations log
  const currentCount = parseInt(matchRow['Brandon_Replies'] || '0', 10) || 0;
  const nztTimestamp = toNZTStr(parsed.deliveredAt);
  return [{
    json: {
      Mobile:           matchRow['Mobile'],
      Brandon_Replies:  String(currentCount + 1),
      _is_manual_reply: true,
      phone_for_conv:   matchRow['Mobile'],
      timestamp:        nztTimestamp,
      message_text:     parsed.message,
    }
  }];
}

// WF1 scheduled send — confirm delivery timestamp
const confirmedTimestamp = toNZTStr(parsed.deliveredAt);

// Idempotency guard: skip if timestamp already confirmed (handles duplicate webhook fires)
const existingTs = (matchRow[tsCol] || '').trim();
if (existingTs && existingTs !== 'PENDING') return [];

const output = { Mobile: matchRow['Mobile'], _is_manual_reply: false };
output[tsCol] = confirmedTimestamp;
return [{ json: output }];

