const parsed = $('Verify & Parse').item.json;
const recipientNorm = normalizeForMatch(parsed.recipient);
const tsCol = getModeFromMessage(parsed.message);
if (!tsCol) return [];

const rows = $input.all();
let matchRow = null;
for (const item of rows) {
  if (normalizeForMatch(item.json['Mobile'] || '') === recipientNorm) {
    matchRow = item.json;
    break;
  }
}
if (!matchRow) return [];

const errorNote = 'FAILED: ' + (parsed.errorMessage || parsed.errorCode || 'unknown error');
const existingNotes = (matchRow['Notes'] || '').trim();
const notes = existingNotes ? existingNotes + '; ' + errorNote : errorNote;

const output = { Mobile: matchRow['Mobile'] };
output[tsCol] = '';  // clear PENDING — lead becomes eligible again
output['Notes'] = notes;
return [{ json: output }];

const json = $input.item.json;

// n8n OpenAI langchain node v2.1 returns:
//   json.output = [{ content: [{ type: "output_text", text: "..." }] }]
let raw = '';
if (Array.isArray(json.output) && json.output[0]) {
  const content = json.output[0].content;
  if (Array.isArray(content)) {
    const chunk = content.find(c => c.text) || content[0];
    if (chunk) raw = chunk.text || '';
  } else if (typeof json.output[0] === 'string') {
    raw = json.output[0];
  }
}
// Fallbacks for other node versions
if (!raw) {
  const candidate = json.text || json.response || json.content ||
    (json.message && (json.message.content || json.message.text)) ||
    (json.choices && json.choices[0] && json.choices[0].message && json.choices[0].message.content) || '';
  raw = typeof candidate === 'string' ? candidate : JSON.stringify(candidate);
}
raw = raw.trim();

const VALID = ['Interested', 'Not Interested', 'Opted Out', 'Question', 'Call Back Later', 'Wrong Role', 'Other'];
let status = 'Other';

try {
  const parsed = JSON.parse(raw);
  const candidate = parsed.status || '';
  if (VALID.includes(candidate)) status = candidate;
} catch(e) {
  // Try regex match first
  const match = raw.match(/"status"\s*:\s*"([^"]+)"/);
  if (match && VALID.includes(match[1])) {
    status = match[1];
  } else {
    // Keyword fallback: scan raw text for any known status
    for (const s of VALID) {
      if (raw.includes(s)) { status = s; break; }
    }
  }
}
return [{ json: { classified_status: status } }];

