const senderNorm = normalizeForMatch(parsed.sender_phone);
const messageText = parsed.message_text;
const receivedStr = toNZTStr(parsed.raw_timestamp);

const rows = $input.all();
let matchRow = null;
for (const item of rows) {
  if (normalizeForMatch(item.json['Mobile'] || '') === senderNorm) {
    matchRow = item.json;
    break;
  }
}
if (!matchRow) return [];

let replyAfter = 'Unknown';
if ((matchRow['F2 Sent'] || '').trim() && matchRow['F2 Sent'] !== 'PENDING') replyAfter = 'F2';
else if ((matchRow['F1 Sent'] || '').trim() && matchRow['F1 Sent'] !== 'PENDING') replyAfter = 'F1';
else if ((matchRow['Initial Sent'] || '').trim()) replyAfter = 'Initial';

const currentLeadReplies = parseInt(matchRow['Lead_Replies'] || '0', 10) || 0;

return [{
  json: {
    Mobile:           matchRow['Mobile'],
    Replied:          'Y',
    'Reply After':    replyAfter,
    'Reply Received': receivedStr,
    'Reply Text':     messageText,
    Status:           $('Parse Classification').item.json.classified_status || 'Other',
    Lead_Replies:     String(currentLeadReplies + 1),
    phone_for_conv:   matchRow['Mobile'],
    message_text:     messageText,
    timestamp:        receivedStr,
    Name:             matchRow['Name'] || '',
    Agency:           matchRow['Agency'] || '',
    City:             matchRow['City'] || '',
  }
}];

